css:
* {
  box-sizing: border-box !important;
}

html, body {
  min-height: 100vh !important;
  background: #080c1a !important;
  color: #c8d8f0 !important;
  font-family: 'Segoe UI', 'Roboto', system-ui, sans-serif !important;
}

/* Фоновый слой — глубокое звёздное небо */
body::before {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  background: 
    radial-gradient(circle at 30% 20%, rgba(20,40,80,0.5) 0%, transparent 60%),
    radial-gradient(circle at 70% 80%, rgba(40,20,60,0.4) 0%, transparent 50%),
    radial-gradient(circle at 50% 50%, #080c1a 0%, #040810 100%);
  background-blend-mode: overlay !important;
}

/* Звёзды (статичные) — фон */
body::after {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  pointer-events: none !important;
  background-image: 
    radial-gradient(1px 1px at 10% 10%, rgba(255,255,255,0.3), transparent),
    radial-gradient(1px 1px at 25% 40%, rgba(255,255,255,0.2), transparent),
    radial-gradient(1px 1px at 55% 15%, rgba(255,255,255,0.4), transparent),
    radial-gradient(1px 1px at 70% 60%, rgba(255,255,255,0.2), transparent),
    radial-gradient(1px 1px at 90% 30%, rgba(255,255,255,0.3), transparent),
    radial-gradient(1px 1px at 15% 80%, rgba(255,255,255,0.2), transparent),
    radial-gradient(1px 1px at 80% 90%, rgba(255,255,255,0.3), transparent),
    radial-gradient(1px 1px at 45% 55%, rgba(255,255,255,0.2), transparent),
    radial-gradient(1px 1px at 5% 50%, rgba(255,255,255,0.2), transparent),
    radial-gradient(1px 1px at 95% 70%, rgba(255,255,255,0.2), transparent);
  background-size: 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%;
  background-repeat: no-repeat;
  animation: twinkle 4s ease-in-out infinite alternate !important;
}

@keyframes twinkle {
  0% { opacity: 0.6; }
  100% { opacity: 1; }
}

/* ===== CANVAS ДЛЯ СЕВЕРНОГО СИЯНИЯ ===== */
#aurora-canvas-layer {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: 1 !important;
  pointer-events: none !important;
  background: transparent !important;
}

/* ===== СНЕЖИНКИ (отдельный слой, поверх сияния, но под контентом) ===== */
#snow-canvas-layer {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: 2 !important;
  pointer-events: none !important;
  background: transparent !important;
}

.p-pageWrapper,
.p-body,
.p-body-inner,
.p-body-main,
.p-body-content,
.p-body-pageContent,
.p-body-header,
.pageContent,
.p-body-inner {
  background: transparent !important;
}

/* Основной контейнер — стеклянный эффект */
.p-body-inner {
  background: rgba(12, 18, 34, 0.7) !important;
  backdrop-filter: blur(16px) !important;
  -webkit-backdrop-filter: blur(16px) !important;
  border-radius: 36px !important;
  padding: 24px !important;
  box-shadow: 0 8px 48px rgba(0, 0, 0, 0.6), inset 0 0 80px rgba(80, 180, 255, 0.05), 0 0 0 1px rgba(100, 200, 255, 0.1) !important;
  border: none !important;
  margin: 16px auto !important;
  position: relative;
  z-index: 3;
  overflow: hidden;
}

/* Лёгкое свечение по краям */
.p-body-inner::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 38px !important;
  background: 
    linear-gradient(135deg, rgba(0, 255, 135, 0.05), transparent 40%, transparent 60%, rgba(96, 239, 255, 0.05)) !important;
  z-index: -1 !important;
  pointer-events: none !important;
}

.p-header {
  background: rgba(12, 18, 34, 0.6) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-bottom: 1px solid rgba(100, 200, 255, 0.1) !important;
  border-radius: 36px 36px 0 0 !important;
  padding: 12px 24px !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.4) !important;
}

.p-header-logo a {
  color: #60efff !important;
  font-weight: 700 !important;
  letter-spacing: 0.5px !important;
  text-shadow: 0 0 30px rgba(96, 239, 255, 0.2) !important;
  font-family: 'Segoe UI', 'Roboto', sans-serif !important;
}

.p-header-logo a:hover {
  text-shadow: 0 0 60px rgba(96, 239, 255, 0.4) !important;
}

.p-nav {
  background: rgba(10, 14, 28, 0.7) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid rgba(100, 200, 255, 0.08) !important;
  box-shadow: 0 4px 32px rgba(0,0,0,0.5) !important;
  padding: 0 16px !important;
}

.p-nav-inner {
  background: transparent !important;
}

.p-nav-list {
  display: flex !important;
  gap: 4px !important;
  background: transparent !important;
}

.p-nav-list .p-navEl {
  color: #b0c8e8 !important;
  font-weight: 500 !important;
  padding: 12px 20px !important;
  border-radius: 40px !important;
  transition: all 0.3s ease !important;
  background: transparent !important;
  font-family: 'Segoe UI', 'Roboto', sans-serif !important;
  position: relative;
}

.p-nav-list .p-navEl:hover {
  background: rgba(96, 239, 255, 0.1) !important;
  color: #e0f0ff !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 0 30px rgba(96, 239, 255, 0.05) !important;
  text-shadow: 0 0 20px rgba(96, 239, 255, 0.1) !important;
}

.p-nav-list .p-navEl.is-selected {
  background: rgba(0, 255, 135, 0.1) !important;
  color: #a0ffd0 !important;
  box-shadow: inset 0 0 0 1px rgba(0, 255, 135, 0.15), 0 0 30px rgba(0, 255, 135, 0.05) !important;
  text-shadow: 0 0 20px rgba(0, 255, 135, 0.1) !important;
}

.p-nav-opposite {
  background: transparent !important;
}

.p-navgroup {
  background: transparent !important;
}

.p-navgroup-link {
  color: #b0c8e8 !important;
  transition: all 0.2s !important;
}

.p-navgroup-link:hover {
  color: #e0f0ff !important;
  background: rgba(96, 239, 255, 0.08) !important;
  border-radius: 40px !important;
  text-shadow: 0 0 20px rgba(96, 239, 255, 0.1) !important;
}

/* Стеклянные блоки */
.block {
  background: rgba(16, 24, 44, 0.5) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(100, 200, 255, 0.08) !important;
  box-shadow: 0 4px 24px rgba(0,0,0,0.4), inset 0 0 60px rgba(80, 180, 255, 0.02) !important;
  padding: 20px !important;
  margin-bottom: 24px !important;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
  position: relative;
  overflow: hidden;
}

.block::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 30px !important;
  background: 
    linear-gradient(135deg, rgba(0, 255, 135, 0.04), transparent 40%, transparent 60%, rgba(96, 239, 255, 0.04)) !important;
  pointer-events: none !important;
  z-index: 0 !important;
}

.block:hover {
  box-shadow: 0 8px 40px rgba(0,0,0,0.6), inset 0 0 60px rgba(80, 180, 255, 0.04) !important;
  transform: translateY(-2px) !important;
  border-color: rgba(100, 200, 255, 0.15) !important;
}

.block-container {
  background: transparent !important;
  border: none !important;
}

.block-body {
  background: transparent !important;
}

.block-minorHeader {
  color: #60efff !important;
  font-weight: 600 !important;
  padding: 12px 16px !important;
  border-bottom: 1px solid rgba(100, 200, 255, 0.08) !important;
  text-shadow: 0 0 20px rgba(96, 239, 255, 0.1) !important;
  font-family: 'Segoe UI', 'Roboto', sans-serif !important;
  letter-spacing: 0.5px;
}

.node {
  background: rgba(18, 28, 48, 0.5) !important;
  border-radius: 24px !important;
  border: 1px solid rgba(100, 200, 255, 0.06) !important;
  padding: 16px 20px !important;
  margin-bottom: 8px !important;
  transition: all 0.3s ease !important;
  position: relative;
}

.node:hover {
  background: rgba(24, 40, 64, 0.7) !important;
  border-color: rgba(100, 200, 255, 0.15) !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 30px rgba(0,0,0,0.4) !important;
}

.node-title a {
  color: #d0e8ff !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(96, 239, 255, 0.05) !important;
}

.node-title a:hover {
  color: #f0f8ff !important;
  text-shadow: 0 0 30px rgba(96, 239, 255, 0.2) !important;
}

.node-stats {
  color: #90b0d0 !important;
}

.node-extra {
  color: #90b0d0 !important;
}

.node-extra-title {
  color: #b0c8e8 !important;
}

.node-extra-title:hover {
  color: #d0e8ff !important;
}

.uix_newIndicator {
  background: rgba(0, 255, 135, 0.15) !important;
  color: #60efff !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(96, 239, 255, 0.2) !important;
}

.node-body {
  background: transparent !important;
  display: flex !important;
  align-items: center !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

.structItem {
  background: rgba(14, 22, 40, 0.4) !important;
  border-radius: 20px !important;
  border: 1px solid rgba(100, 200, 255, 0.05) !important;
  padding: 12px 16px !important;
  margin-bottom: 6px !important;
  transition: all 0.25s ease !important;
  display: flex !important;
  align-items: stretch !important;
  flex-wrap: nowrap !important;
  gap: 12px !important;
}

.structItem:hover {
  background: rgba(22, 36, 60, 0.6) !important;
  border-color: rgba(100, 200, 255, 0.12) !important;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3) !important;
}

.structItem-cell {
  display: flex !important;
  align-items: center !important;
}

.structItem-cell--icon {
  flex: 0 0 48px !important;
  min-width: 48px !important;
  justify-content: center !important;
}

.structItem-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  flex-direction: column !important;
  align-items: stretch !important;
}

.structItem-cell--meta {
  flex: 0 0 100px !important;
  justify-content: center !important;
  align-items: flex-start !important;
}

.structItem-cell--latest {
  flex: 0 0 120px !important;
  justify-content: center !important;
  align-items: flex-end !important;
  text-align: right !important;
}

.structItem-cell--iconEnd {
  flex: 0 0 32px !important;
  justify-content: center !important;
}

.structItem-title {
  color: #d0e8ff !important;
  font-weight: 500 !important;
}

.structItem-title a {
  color: #d0e8ff !important;
}

.structItem-title a:hover {
  color: #f0f8ff !important;
  text-shadow: 0 0 30px rgba(96, 239, 255, 0.15) !important;
}

.structItem-statuses {
  color: #90b0d0 !important;
  display: flex !important;
  gap: 4px !important;
  align-items: center !important;
}

.structItem-status--locked {
  color: #ff8888 !important;
}

.structItem-status--sticky {
  color: #f0c080 !important;
}

.structItem-minor {
  color: #8098b8 !important;
  font-size: 13px !important;
}

.structItem-minor a {
  color: #90b0d0 !important;
}

.structItem-minor a:hover {
  color: #b0c8e8 !important;
}

.structItem-parts {
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
}

.structItem-parts li {
  display: inline !important;
}

.structItem-latestDate {
  color: #90b0d0 !important;
}

.structItem--quickCreate {
  background: rgba(14, 22, 40, 0.3) !important;
  border: 1px dashed rgba(100, 200, 255, 0.15) !important;
  border-radius: 20px !important;
}

.structItem--quickCreate textarea {
  background: rgba(8, 12, 24, 0.6) !important;
  border: 1px solid rgba(100, 200, 255, 0.1) !important;
  color: #c8d8f0 !important;
  border-radius: 20px !important;
  padding: 12px !important;
}

.structItem--quickCreate textarea:focus {
  border-color: rgba(96, 239, 255, 0.3) !important;
  box-shadow: 0 0 0 4px rgba(96, 239, 255, 0.05) !important;
}

.message {
  background: rgba(16, 24, 44, 0.5) !important;
  backdrop-filter: blur(6px) !important;
  -webkit-backdrop-filter: blur(6px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(100, 200, 255, 0.06) !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  transition: all 0.3s ease !important;
  overflow: hidden !important;
  position: relative;
}

.message:hover {
  background: rgba(24, 38, 64, 0.6) !important;
  border-color: rgba(100, 200, 255, 0.15) !important;
  box-shadow: 0 8px 32px rgba(0,0,0,0.5) !important;
  transform: translateY(-2px) !important;
}

.message-inner {
  background: transparent !important;
  display: flex !important;
  flex-wrap: wrap !important;
}

.message-cell {
  background: transparent !important;
  padding: 16px !important;
}

.message-cell--user {
  background: rgba(10, 16, 30, 0.3) !important;
  border-right: 1px solid rgba(100, 200, 255, 0.06) !important;
  border-radius: 28px 0 0 20px !important;
  min-width: 180px !important;
  flex: 0 0 180px !important;
}

.message-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  border-radius: 0 28px 20px 0 !important;
}

.message-user {
  background: transparent !important;
}

.message-avatar {
  text-align: center !important;
  margin-bottom: 8px !important;
}

.message-avatar .avatar {
  border-radius: 50% !important;
  border: 2px solid rgba(96, 239, 255, 0.2) !important;
  transition: all 0.3s ease !important;
  box-shadow: 0 0 20px rgba(96, 239, 255, 0.05) !important;
}

.message-avatar .avatar:hover {
  transform: scale(1.08) !important;
  border-color: rgba(0, 255, 135, 0.4) !important;
  box-shadow: 0 0 40px rgba(0, 255, 135, 0.15) !important;
}

.message-userDetails {
  text-align: center !important;
}

.message-name {
  font-weight: 600 !important;
  font-size: 15px !important;
  font-family: 'Segoe UI', 'Roboto', sans-serif !important;
}

.message-name a {
  color: #d0e8ff !important;
}

.message-name a:hover {
  color: #f0f8ff !important;
  text-shadow: 0 0 30px rgba(96, 239, 255, 0.2) !important;
}

.userBanner {
  background: rgba(0, 255, 135, 0.08) !important;
  border-radius: 40px !important;
  padding: 2px 14px !important;
  font-size: 11px !important;
  color: #b0c8e8 !important;
  display: inline-block !important;
  margin-top: 4px !important;
  text-shadow: 0 0 10px rgba(96, 239, 255, 0.05) !important;
}

.userBanner--red {
  background: rgba(200, 80, 80, 0.15) !important;
  color: #ff8888 !important;
}

.userBanner--primary {
  background: rgba(96, 239, 255, 0.08) !important;
  color: #b0c8e8 !important;
}

.message-userExtras {
  margin-top: 8px !important;
  font-size: 12px !important;
  color: #8098b8 !important;
}

.message-userExtras .pairs {
  padding: 2px 0 !important;
}

.message-userExtras .pairs dt {
  color: #607890 !important;
}

.message-userExtras .pairs dd {
  color: #a0b8d8 !important;
}

.message-attribution {
  background: rgba(8, 12, 24, 0.2) !important;
  padding: 8px 16px !important;
  border-bottom: 1px solid rgba(100, 200, 255, 0.04) !important;
}

.message-attribution a {
  color: #8098b8 !important;
}

.message-attribution a:hover {
  color: #b0c8e8 !important;
}

.message-newIndicator {
  background: rgba(0, 255, 135, 0.12) !important;
  color: #60efff !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(96, 239, 255, 0.2) !important;
}

.message-content {
  padding: 16px !important;
}

.message-body {
  color: #d0e0f0 !important;
  font-size: 15px !important;
  line-height: 1.7 !important;
}

.message-body .bbWrapper {
  color: #d0e0f0 !important;
}

.message-body a {
  color: #60efff !important;
}

.message-body a:hover {
  color: #a0f0ff !important;
  text-shadow: 0 0 30px rgba(96, 239, 255, 0.2) !important;
}

.message-body .bbMediaWrapper {
  border-radius: 20px !important;
  overflow: hidden !important;
  background: rgba(8, 12, 24, 0.6) !important;
  border: 1px solid rgba(100, 200, 255, 0.08) !important;
}

.message-body .bbMediaWrapper iframe {
  border-radius: 20px !important;
}

.message-fields--before {
  background: rgba(10, 16, 30, 0.3) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  margin-bottom: 12px !important;
  border: 1px solid rgba(100, 200, 255, 0.05) !important;
}

.message-fields--before .pairs {
  padding: 2px 0 !important;
}

.message-fields--before .pairs dt {
  color: #607890 !important;
  font-weight: 500 !important;
}

.message-fields--before .pairs dd {
  color: #b0c8e8 !important;
}

.message-signature {
  background: rgba(8, 12, 24, 0.15) !important;
  border-top: 1px solid rgba(100, 200, 255, 0.04) !important;
  padding: 12px 16px !important;
  margin-top: 12px !important;
  border-radius: 0 0 20px 20px !important;
  font-size: 13px !important;
  color: #8098b8 !important;
  max-height: 100px !important;
  overflow: hidden !important;
  transition: max-height 0.3s ease !important;
}

.message-signature--expanded {
  max-height: 500px !important;
}

.message-signature .bbWrapper {
  color: #8098b8 !important;
}

.message-signature a {
  color: #70a0c0 !important;
}

.message-signature a:hover {
  color: #90c0e0 !important;
}

.uix_signatureExpand {
  cursor: pointer !important;
  color: #607890 !important;
  font-size: 11px !important;
  text-align: center !important;
  padding: 4px !important;
  border-radius: 40px !important;
  background: rgba(100, 200, 255, 0.04) !important;
  margin-bottom: 6px !important;
  transition: all 0.2s !important;
}

.uix_signatureExpand:hover {
  background: rgba(100, 200, 255, 0.08) !important;
  color: #b0c8e8 !important;
}

.actionBar {
  background: rgba(8, 12, 24, 0.2) !important;
  border-top: 1px solid rgba(100, 200, 255, 0.04) !important;
  padding: 6px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  border-radius: 0 0 20px 20px !important;
}

.actionBar-action {
  background: transparent !important;
  color: #8098b8 !important;
  padding: 4px 12px !important;
  border-radius: 40px !important;
  font-size: 13px !important;
  transition: all 0.2s !important;
  cursor: pointer !important;
}

.actionBar-action:hover {
  background: rgba(96, 239, 255, 0.08) !important;
  color: #c0d8f0 !important;
}

.actionBar-action--reaction {
  background: rgba(96, 239, 255, 0.04) !important;
}

.actionBar-action--reaction:hover {
  background: rgba(96, 239, 255, 0.12) !important;
}

.actionBar-action--menuTrigger {
  color: #607890 !important;
}

.actionBar-action--menuTrigger:hover {
  background: rgba(100, 200, 255, 0.06) !important;
}

.blockStatus {
  background: rgba(12, 18, 34, 0.6) !important;
  border-radius: 40px !important;
  border: 1px solid rgba(100, 200, 255, 0.1) !important;
  padding: 8px 24px !important;
  color: #b0c8e8 !important;
  backdrop-filter: blur(4px) !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 8px !important;
}

.blockStatus-message {
  color: #b0c8e8 !important;
}

.blockStatus-message--locked {
  border-color: #cc6666 !important;
  color: #ff8888 !important;
  background: rgba(200, 80, 80, 0.08) !important;
  border-radius: 40px !important;
  padding: 4px 16px !important;
}

.message-newIndicator,
.uix_newIndicator {
  background: rgba(0, 255, 135, 0.12) !important;
  color: #60efff !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(96, 239, 255, 0.2) !important;
}

.message--deleted {
  opacity: 0.5 !important;
  background: rgba(200, 80, 80, 0.05) !important;
  border-color: rgba(200, 80, 80, 0.08) !important;
}

.messageNotice--deleted {
  background: rgba(200, 80, 80, 0.04) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
