(function() {
  // ===== СЕВЕРНОЕ СИЯНИЕ (волны) =====
  function initAurora() {
    const canvas = document.createElement('canvas');
    canvas.id = 'aurora-canvas-layer';
    canvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:1;pointer-events:none;background:transparent;';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let W, H;
    let time = 0;

    function resize() {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resize);
    resize();

    // Параметры волн: цвет, амплитуда, частота, скорость, смещение по Y
    const waves = [
      { color: 'rgba(0, 255, 135, 0.15)', amplitude: 80, frequency: 0.008, speed: 0.6, yOffset: 0.2 },
      { color: 'rgba(96, 239, 255, 0.12)', amplitude: 100, frequency: 0.012, speed: 0.8, yOffset: 0.4 },
      { color: 'rgba(167, 139, 250, 0.10)', amplitude: 120, frequency: 0.006, speed: 0.4, yOffset: 0.6 },
      { color: 'rgba(0, 200, 255, 0.08)', amplitude: 60, frequency: 0.015, speed: 1.0, yOffset: 0.1 },
    ];

    function draw() {
      time++;
      ctx.clearRect(0, 0, W, H);

      // Рисуем каждую волну
      for (const wave of waves) {
        ctx.beginPath();
        ctx.moveTo(0, H * wave.yOffset);
        for (let x = 0; x <= W; x += 2) {
          const y = H * wave.yOffset 
            + Math.sin(x * wave.frequency + time * wave.speed * 0.02) * wave.amplitude
            + Math.sin(x * wave.frequency * 0.5 + time * wave.speed * 0.01) * wave.amplitude * 0.4
            + Math.sin(x * wave.frequency * 2 + time * wave.speed * 0.03) * wave.amplitude * 0.2;
          ctx.lineTo(x, y);
        }
        ctx.strokeStyle = wave.color;
        ctx.lineWidth = 2.5;
        ctx.shadowColor = wave.color;
        ctx.shadowBlur = 20;
        ctx.stroke();
        ctx.shadowBlur = 0;
      }

      requestAnimationFrame(draw);
    }

    draw();
  }

  // ===== СНЕЖИНКИ =====
  function initSnow() {
    const canvas = document.createElement('canvas');
    canvas.id = 'snow-canvas-layer';
    canvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:2;pointer-events:none;background:transparent;';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let W, H;
    let flakes = [];
    const FLAKE_COUNT = 80;

    function resize() {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resize);
    resize();

    class Flake {
      constructor() {
        this.reset();
        this.x = Math.random() * W;
        this.y = Math.random() * H;
        this.size = 1 + Math.random() * 3;
        this.speed = 0.3 + Math.random() * 0.6;
        this.wind = (Math.random() - 0.5) * 0.2;
        this.opacity = 0.3 + Math.random() * 0.4;
      }
      reset() {
        this.x = Math.random() * W;
        this.y = -10;
        this.size = 1 + Math.random() * 3;
        this.speed = 0.3 + Math.random() * 0.6;
        this.wind = (Math.random() - 0.5) * 0.2;
        this.opacity = 0.3 + Math.random() * 0.4;
      }
      update() {
        this.y += this.speed;
        this.x += this.wind + Math.sin(this.y * 0.01) * 0.2;
        if (this.y > H + 10) {
          this.reset();
          this.y = -10;
        }
        if (this.x < -10) this.x = W + 10;
        if (this.x > W + 10) this.x = -10;
      }
      draw() {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${this.opacity})`;
        ctx.shadowColor = 'rgba(255, 255, 255, 0.2)';
        ctx.shadowBlur = 8;
        ctx.fill();
        ctx.shadowBlur = 0;
      }
    }

    for (let i = 0; i < FLAKE_COUNT; i++) {
      flakes.push(new Flake());
    }

    function draw() {
      ctx.clearRect(0, 0, W, H);
      for (const flake of flakes) {
        flake.update();
        flake.draw();
      }
      requestAnimationFrame(draw);
    }

    draw();
  }

  // Запускаем оба эффекта
  initAurora();
  initSnow();

  console.log('[Aurora Borealis] Северное сияние и снег активированы.');
})();
